mapper.sql:
select rr.id as record_id, coalesce(rt.title, concat('Reading Test #', rr.test_id)) as name, 'READING' as module, case when rr.is_deleted = 1 then 'DELETED' else 'COMPLETED' end as status, rr.total_score as score, cast(rr.total_score as char) as score_text, rr.created_time as updated_time, rr.created_time as created_time, rr.is_deleted as is_deleted, null as deleted_time from reading_record rr left join reading_test rt on rt.id = rr.test_id where rr.user_id = #{userId}
union all
select lr.id as record_id, coalesce(lt.title, concat('Listening Test #', lr.test_id)) as name, 'LISTENING' as module, case when lr.is_deleted = 1 then 'DELETED' else 'COMPLETED' end as status, lr.total_score as score, cast(lr.total_score as char) as score_text, lr.created_time as updated_time, lr.created_time as created_time, lr.is_deleted as is_deleted, null as deleted_time from listening_record lr left join listening_test lt on lt.id = lr.test_id where lr.user_id = #{userId}
union all
select wr.id as record_id, coalesce(wq.title, concat('Writing Question #', wr.question_id)) as name, 'WRITING' as module, case when wr.is_deleted = 1 then 'DELETED' else wr.ai_status end as status, wr.ai_score as score, cast(wr.ai_score as char) as score_text, case when wr.is_deleted = 1 and wr.deleted_time is not null then wr.deleted_time else wr.created_time end as updated_time, wr.created_time as created_time, wr.is_deleted as is_deleted, wr.deleted_time as deleted_time from writing_record wr left join writing_question wq on wq.id = wr.question_id where wr.user_id = #{userId}
union all
select sr.id as record_id, coalesce(sq.question_text, concat('Speaking Question #', sr.question_id)) as name, 'SPEAKING' as module, case when sr.is_deleted = 1 then 'DELETED' when sr.answer_status is not null and sr.answer_status != '' then sr.answer_status else sr.ai_status end as status, sr.overall_score as score, cast(sr.overall_score as char) as score_text, case when sr.is_deleted = 1 and sr.deleted_time is not null then sr.deleted_time when sr.updated_time is not null then sr.updated_time else sr.created_time end as updated_time, sr.created_time as created_time, sr.is_deleted as is_deleted, sr.deleted_time as deleted_time from speaking_record sr left join speaking_question sq on sq.id = sr.question_id where sr.user_id = #{userId}

mapper.select:
select records.record_id, records.name, records.module, records.status, records.score, records.score_text, records.updated_time, records.created_time, records.is_deleted, records.deleted_time from (
) records
limit #{limit} offset #{offset}
